81	// =============================================================================
82	// Traits
83	// =============================================================================
84	
85	/// Universal "what every cooperative group exposes" trait.
86	///
87	/// Every group type — [`Grid`], [`Cluster`], [`ThreadBlock`],
88	/// [`WarpTile<N>`], [`CoalescedThreads`] — implements this. The three
89	/// methods are the entire reason cooperative groups exist as an
90	/// abstraction: at every level of the CUDA hierarchy you can ask "how
91	/// many of us are there", "which one am I", and "wait for everyone".
92	pub trait ThreadGroup: Copy {
93	    /// Number of threads in this group.
94	    fn size(&self) -> u32;
95	
96	    /// This thread's index inside the group, `0..size()`.
97	    fn thread_rank(&self) -> u32;
98	
99	    /// Barrier scoped to this group. Every thread in the group must reach
100	    /// this call before any of them proceeds.
101	    fn sync(&self);
102	}
103	
104	/// Operations that only warp-scoped groups support.
105	///
106	/// Implemented by [`WarpTile<N>`] and [`CoalescedThreads`]. These are the
107	/// register-to-register collectives backed by PTX `shfl.sync` / `vote.sync`
108	/// / `match.sync` — they do not work at block, cluster, or grid scope.
109	///
110	/// All `*_rank` arguments and return values are **tile-relative**: lane 0
111	/// of a [`WarpTile<16>`] is the lane at warp position 0 *or* 16,
112	/// whichever bucket this thread is in. The implementation translates
113	/// to/from absolute warp lanes internally.
114	pub trait WarpCollective: ThreadGroup {
115	    /// Bitmask: bit `k` (within this group) set iff lane `k`'s `predicate` is true.
116	    ///
117	    /// PTX `vote.sync.ballot.b32` with the group's participation mask.
118	    fn ballot(&self, predicate: bool) -> u32;
119	
120	    /// True iff every lane in this group has `predicate == true`.
121	    ///
122	    /// PTX `vote.sync.all.pred`.
123	    fn all(&self, predicate: bool) -> bool;
124	
125	    /// True iff at least one lane in this group has `predicate == true`.
126	    ///
127	    /// PTX `vote.sync.any.pred`.
128	    fn any(&self, predicate: bool) -> bool;
129	
130	    /// Read `var` from the lane at position `src_rank` in this group.
131	    ///
132	    /// PTX `shfl.sync.idx.b32`. `src_rank` is tile-relative (`0..size()`).
133	    fn shfl(&self, var: u32, src_rank: u32) -> u32;
134	
135	    /// Butterfly exchange under this group's mask.
136	    ///
137	    /// PTX `shfl.sync.bfly.b32`. `lane_mask` is the XOR mask; for
138	    /// pairwise swaps of size `2^k` use `lane_mask = 1 << k`.
139	    fn shfl_xor(&self, var: u32, lane_mask: u32) -> u32;
140	
141	    /// Read from `(my_rank + delta)` within this group.
142	    ///
143	    /// PTX `shfl.sync.down.b32`. Lanes near the high end of the group
144	    /// receive their own value (no wraparound).
145	    fn shfl_down(&self, var: u32, delta: u32) -> u32;
146	
147	    /// Read from `(my_rank - delta)` within this group.
148	    ///
149	    /// PTX `shfl.sync.up.b32`. Lanes near the low end of the group
150	    /// receive their own value (no wraparound).
151	    fn shfl_up(&self, var: u32, delta: u32) -> u32;
152	
153	    /// `f32` variant of [`shfl`](Self::shfl).
154	    fn shfl_f32(&self, var: f32, src_rank: u32) -> f32;
155	
156	    /// `f32` variant of [`shfl_xor`](Self::shfl_xor).
157	    fn shfl_xor_f32(&self, var: f32, lane_mask: u32) -> f32;
158	
159	    /// `f32` variant of [`shfl_down`](Self::shfl_down).
160	    fn shfl_down_f32(&self, var: f32, delta: u32) -> f32;
161	
162	    /// `f32` variant of [`shfl_up`](Self::shfl_up).
163	    fn shfl_up_f32(&self, var: f32, delta: u32) -> f32;
164	
165	    /// Bitmask of lanes in this group whose `value` equals mine.
166	    ///
167	    /// PTX `match.any.sync.b32` (sm_70+). Bits are absolute warp-lane
168	    /// positions; the implementation already AND-s the raw hardware
169	    /// result with the group's participation mask, so the returned
170	    /// bits are guaranteed to be a subset of `mask()`.
171	    fn match_any(&self, value: u32) -> u32;
172	
173	    /// 64-bit value variant of [`match_any`](Self::match_any).
174	    ///
175	    /// PTX `match.any.sync.b64` (sm_70+).
176	    fn match_any_i64(&self, value: u64) -> u32;
177	
178	    /// Group's participation mask if every lane in the group has the same
179	    /// `value`, else 0.
180	    ///
181	    /// PTX `match.all.sync.b32` (sm_70+). Recover the all-match predicate
182	    /// as `result != 0`.
183	    fn match_all(&self, value: u32) -> u32;
184	
185	    /// 64-bit value variant of [`match_all`](Self::match_all).
186	    fn match_all_i64(&self, value: u64) -> u32;
187	}
