193	/// Linearize the (x, y, z) thread index inside the current block.
194	#[inline(always)]
195	fn thread_in_block_linear() -> u32 {
196	    let tx = thread::threadIdx_x();
197	    let ty = thread::threadIdx_y();
198	    let tz = thread::threadIdx_z();
199	    let dx = thread::blockDim_x();
200	    let dy = thread::blockDim_y();
201	    (tz * dy + ty) * dx + tx
202	}
203	
204	/// Total threads per block.
205	#[inline(always)]
206	fn threads_per_block() -> u32 {
207	    thread::blockDim_x() * thread::blockDim_y() * thread::blockDim_z()
208	}
209	
210	/// Total blocks per grid.
211	#[inline(always)]
212	fn blocks_per_grid() -> u32 {
213	    thread::gridDim_x() * thread::gridDim_y() * thread::gridDim_z()
214	}
215	
216	/// Linear block index inside the grid.
217	#[inline(always)]
218	fn block_in_grid_linear() -> u32 {
219	    let bx = thread::blockIdx_x();
220	    let by = thread::blockIdx_y();
221	    let bz = thread::blockIdx_z();
222	    let gx = thread::gridDim_x();
223	    let gy = thread::gridDim_y();
224	    (bz * gy + by) * gx + bx
225	}
