359	    pub fn tiled_partition<const N: u32>(self) -> WarpTile<N> {
360	        const {
361	            assert!(
362	                N == 1 || N == 2 || N == 4 || N == 8 || N == 16 || N == 32,
363	                "WarpTile size must be 1, 2, 4, 8, 16, or 32",
364	            );
365	        }
366	        WarpTile { _priv: () }
367	    }
368	}
