387	// =============================================================================
388	// WarpTile<N>
389	// =============================================================================
390	
391	/// A tile of `N` lanes inside the current warp.
392	///
393	/// `N` is a compile-time constant, so the participation mask folds away
394	/// at codegen and the resulting PTX is byte-identical to a hand-written
395	/// `*_sync(mask, ...)` call.
396	///
397	/// Get one from [`ThreadBlock::tiled_partition`]:
398	///
399	/// ```rust,ignore
400	/// let warp = this_thread_block().tiled_partition::<32>();
401	/// let half = this_thread_block().tiled_partition::<16>();
402	/// ```
403	///
404	/// All [`WarpCollective`] methods take and return values relative to
405	/// **this tile**: `shfl(var, 0)` reads from the lowest lane of *this*
406	/// tile, not from absolute warp lane 0.
407	#[derive(Copy, Clone, Debug)]
408	pub struct WarpTile<const N: u32> {
409	    _priv: (),
410	}
411	
412	impl<const N: u32> WarpTile<N> {
413	    /// Participation mask for this thread's tile.
414	    #[inline(always)]
415	    fn mask(&self) -> u32 {
416	        if N == 32 {
417	            u32::MAX
418	        } else {
419	            let lane = warp::lane_id();
420	            let tile_idx = lane / N;
421	            ((1u32 << N) - 1) << (tile_idx * N)
422	        }
423	    }
424	
425	    /// Lane mask aligned to the start of this tile within the warp.
426	    #[inline(always)]
427	    fn tile_base_lane(&self) -> u32 {
428	        warp::lane_id() & !(N - 1)
429	    }
430	}
431	
432	impl<const N: u32> ThreadGroup for WarpTile<N> {
433	    #[inline(always)]
434	    fn size(&self) -> u32 {
435	        N
436	    }
437	
438	    #[inline(always)]
439	    fn thread_rank(&self) -> u32 {
440	        warp::lane_id() & (N - 1)
441	    }
442	
443	    #[inline(always)]
444	    fn sync(&self) {
445	        if N == 32 {
446	            warp::sync_mask(u32::MAX);
447	        } else {
448	            warp::sync_mask(self.mask());
449	        }
450	    }
451	}
452	
453	impl<const N: u32> WarpCollective for WarpTile<N> {
454	    #[inline(always)]
455	    fn ballot(&self, predicate: bool) -> u32 {
456	        let raw = warp::ballot_sync(self.mask(), predicate);
457	        if N == 32 {
458	            raw
459	        } else {
460	            (raw >> self.tile_base_lane()) & ((1u32 << N) - 1)
461	        }
462	    }
463	
464	    #[inline(always)]
465	    fn all(&self, predicate: bool) -> bool {
466	        warp::all_sync(self.mask(), predicate)
467	    }
468	
469	    #[inline(always)]
470	    fn any(&self, predicate: bool) -> bool {
471	        warp::any_sync(self.mask(), predicate)
472	    }
473	
474	    #[inline(always)]
475	    fn shfl(&self, var: u32, src_rank: u32) -> u32 {
476	        let abs_src = self.tile_base_lane() | (src_rank & (N - 1));
477	        warp::shuffle_sync(self.mask(), var, abs_src)
478	    }
479	
480	    #[inline(always)]
481	    fn shfl_xor(&self, var: u32, lane_mask: u32) -> u32 {
482	        warp::shuffle_xor_sync(self.mask(), var, lane_mask)
483	    }
484	
485	    #[inline(always)]
486	    fn shfl_down(&self, var: u32, delta: u32) -> u32 {
487	        warp::shuffle_down_sync(self.mask(), var, delta)
488	    }
489	
490	    #[inline(always)]
491	    fn shfl_up(&self, var: u32, delta: u32) -> u32 {
492	        warp::shuffle_up_sync(self.mask(), var, delta)
493	    }
494	
495	    #[inline(always)]
496	    fn shfl_f32(&self, var: f32, src_rank: u32) -> f32 {
497	        let abs_src = self.tile_base_lane() | (src_rank & (N - 1));
498	        warp::shuffle_f32_sync(self.mask(), var, abs_src)
499	    }
500	
501	    #[inline(always)]
502	    fn shfl_xor_f32(&self, var: f32, lane_mask: u32) -> f32 {
503	        warp::shuffle_xor_f32_sync(self.mask(), var, lane_mask)
504	    }
505	
506	    #[inline(always)]
507	    fn shfl_down_f32(&self, var: f32, delta: u32) -> f32 {
508	        warp::shuffle_down_f32_sync(self.mask(), var, delta)
509	    }
510	
511	    #[inline(always)]
512	    fn shfl_up_f32(&self, var: f32, delta: u32) -> f32 {
513	        warp::shuffle_up_f32_sync(self.mask(), var, delta)
514	    }
515	
516	    #[inline(always)]
517	    fn match_any(&self, value: u32) -> u32 {
518	        warp::match_any_sync(self.mask(), value) & self.mask()
519	    }
520	
521	    #[inline(always)]
522	    fn match_any_i64(&self, value: u64) -> u32 {
523	        warp::match_any_i64_sync(self.mask(), value) & self.mask()
524	    }
525	
526	    #[inline(always)]
527	    fn match_all(&self, value: u32) -> u32 {
528	        warp::match_all_sync(self.mask(), value)
529	    }
530	
531	    #[inline(always)]
532	    fn match_all_i64(&self, value: u64) -> u32 {
533	        warp::match_all_i64_sync(self.mask(), value)
534	    }
535	}
