537	// =============================================================================
538	// CoalescedThreads
539	// =============================================================================
540	
541	/// The set of warp lanes that are currently converged with this thread.
542	///
543	/// Construct with [`coalesced_threads`]. The participation mask is
544	/// captured at construction time from PTX `activemask.b32`, so the
545	/// group is stable across subsequent collectives even if control flow
546	/// later diverges further.
547	///
548	/// Use this when you're already inside a divergent branch and need a
549	/// type-safe handle for the lanes that took it. For straight-line warp
550	/// code use [`WarpTile<32>`] instead.
551	#[derive(Copy, Clone, Debug)]
552	pub struct CoalescedThreads {
553	    mask: u32,
554	}
555	
556	/// Capture the currently-converged lanes as a [`CoalescedThreads`] group.
557	#[inline(always)]
558	pub fn coalesced_threads() -> CoalescedThreads {
559	    CoalescedThreads {
560	        mask: warp::active_mask(),
561	    }
562	}
563	
564	impl CoalescedThreads {
565	    /// The captured participation mask.
566	    #[inline(always)]
567	    pub fn raw_mask(&self) -> u32 {
568	        self.mask
569	    }
570	}
571	
572	impl ThreadGroup for CoalescedThreads {
573	    #[inline(always)]
574	    fn size(&self) -> u32 {
575	        self.mask.count_ones()
576	    }
577	
578	    #[inline(always)]
579	    fn thread_rank(&self) -> u32 {
580	        let lane = warp::lane_id();
581	        let lower = self.mask & ((1u32 << lane) - 1);
582	        lower.count_ones()
583	    }
584	
585	    #[inline(always)]
586	    fn sync(&self) {
587	        warp::sync_mask(self.mask);
588	    }
589	}
590	
591	impl WarpCollective for CoalescedThreads {
592	    #[inline(always)]
593	    fn ballot(&self, predicate: bool) -> u32 {
594	        warp::ballot_sync(self.mask, predicate) & self.mask
595	    }
596	
597	    #[inline(always)]
598	    fn all(&self, predicate: bool) -> bool {
599	        warp::all_sync(self.mask, predicate)
600	    }
601	
602	    #[inline(always)]
603	    fn any(&self, predicate: bool) -> bool {
604	        warp::any_sync(self.mask, predicate)
605	    }
606	
607	    // `shfl` translates the group-relative `src_rank` to an absolute
608	    // warp lane (the lane whose own `thread_rank` inside the coalesced
609	    // group equals `src_rank`) by popping the `src_rank` lowest set
610	    // bits of the participation mask. When `src_rank` is a runtime
611	    // value the loop survives as a small `popc`/branch sequence; when
612	    // it folds to a constant the loop unrolls.
613	    //
614	    // `shfl_xor`/`shfl_down`/`shfl_up` forward `lane_mask`/`delta`
615	    // straight to the hardware, which interprets them in **absolute
616	    // warp-lane** terms — not relative to the coalesced group. For a
617	    // sparse mask "shift my rank by k" has no clean cross-lane
618	    // analogue, so callers wanting rank-relative semantics on
619	    // `CoalescedThreads` should use `shfl` with an explicit target
620	    // rank instead.
621	
622	    #[inline(always)]
623	    fn shfl(&self, var: u32, src_rank: u32) -> u32 {
624	        let mut m = self.mask;
625	        let mut k = src_rank;
626	        while k > 0 {
627	            m &= m - 1;
628	            k -= 1;
629	        }
630	        let abs_lane = m.trailing_zeros();
631	        warp::shuffle_sync(self.mask, var, abs_lane)
632	    }
633	
634	    #[inline(always)]
635	    fn shfl_xor(&self, var: u32, lane_mask: u32) -> u32 {
636	        warp::shuffle_xor_sync(self.mask, var, lane_mask)
637	    }
638	
639	    #[inline(always)]
640	    fn shfl_down(&self, var: u32, delta: u32) -> u32 {
641	        warp::shuffle_down_sync(self.mask, var, delta)
642	    }
643	
644	    #[inline(always)]
645	    fn shfl_up(&self, var: u32, delta: u32) -> u32 {
646	        warp::shuffle_up_sync(self.mask, var, delta)
647	    }
648	
649	    #[inline(always)]
650	    fn shfl_f32(&self, var: f32, src_rank: u32) -> f32 {
651	        let mut m = self.mask;
652	        let mut k = src_rank;
653	        while k > 0 {
654	            m &= m - 1;
655	            k -= 1;
656	        }
657	        let abs_lane = m.trailing_zeros();
658	        warp::shuffle_f32_sync(self.mask, var, abs_lane)
659	    }
660	
661	    #[inline(always)]
662	    fn shfl_xor_f32(&self, var: f32, lane_mask: u32) -> f32 {
663	        warp::shuffle_xor_f32_sync(self.mask, var, lane_mask)
664	    }
665	
666	    #[inline(always)]
667	    fn shfl_down_f32(&self, var: f32, delta: u32) -> f32 {
668	        warp::shuffle_down_f32_sync(self.mask, var, delta)
669	    }
670	
671	    #[inline(always)]
672	    fn shfl_up_f32(&self, var: f32, delta: u32) -> f32 {
673	        warp::shuffle_up_f32_sync(self.mask, var, delta)
674	    }
675	
676	    #[inline(always)]
677	    fn match_any(&self, value: u32) -> u32 {
678	        warp::match_any_sync(self.mask, value) & self.mask
679	    }
680	
681	    #[inline(always)]
682	    fn match_any_i64(&self, value: u64) -> u32 {
683	        warp::match_any_i64_sync(self.mask, value) & self.mask
684	    }
685	
686	    #[inline(always)]
687	    fn match_all(&self, value: u32) -> u32 {
688	        warp::match_all_sync(self.mask, value)
689	    }
690	
691	    #[inline(always)]
692	    fn match_all_i64(&self, value: u64) -> u32 {
693	        warp::match_all_i64_sync(self.mask, value)
694	    }
695	}
