697	// =============================================================================
698	// Reductions and scans
699	// =============================================================================
700	
701	/// Combiner operations for [`warp_reduce`], [`warp_scan`], [`block_reduce`],
702	/// and [`block_scan`].
703	///
704	/// Each combiner is a unit struct (`Sum`, `Min`, ...) that implements
705	/// `ReduceOp<T>` for one or more value types `T`. The unit lives in this
706	/// submodule so the names don't pollute the parent `cooperative_groups`
707	/// namespace; users typically write
708	/// `use cuda_device::cooperative_groups::ops::Sum;` at the call site.
709	///
710	/// Every `(combine, identity)` pair is a commutative associative monoid,
711	/// so the result is independent of the shuffle topology used to compute it.
712	pub mod ops {
713	    /// Binary reduction operation over values of type `T`.
714	    ///
715	    /// For determinism across the butterfly / Kogge-Stone topologies used
716	    /// by the reduce and scan primitives, `(combine, identity)` must form
717	    /// a commutative monoid. All operations in this module satisfy that.
718	    pub trait ReduceOp<T> {
719	        /// Identity element: `combine(identity(), x) == x` for all `x`.
720	        fn identity() -> T;
721	        /// Binary combiner. Must be associative and commutative.
722	        fn combine(a: T, b: T) -> T;
723	    }
724	
725	    /// Sum: wrapping integer addition; IEEE-754 add for floats.
726	    #[derive(Copy, Clone, Debug)]
727	    pub struct Sum;
728	
729	    /// Minimum (non-NaN-aware for floats — see the `f32` impl).
730	    #[derive(Copy, Clone, Debug)]
731	    pub struct Min;
732	
733	    /// Maximum (non-NaN-aware for floats — see the `f32` impl).
734	    #[derive(Copy, Clone, Debug)]
735	    pub struct Max;
736	
737	    /// Bitwise AND (`u32` only — meaningless for signed/float).
738	    #[derive(Copy, Clone, Debug)]
739	    pub struct BitAnd;
740	
741	    /// Bitwise OR (`u32` only).
742	    #[derive(Copy, Clone, Debug)]
743	    pub struct BitOr;
744	
745	    /// Bitwise XOR (`u32` only).
746	    #[derive(Copy, Clone, Debug)]
747	    pub struct BitXor;
748	
749	    // --- u32 ---
750	    impl ReduceOp<u32> for Sum {
751	        #[inline(always)]
752	        fn identity() -> u32 {
753	            0
754	        }
755	        #[inline(always)]
756	        fn combine(a: u32, b: u32) -> u32 {
