879	/// Scalars that ride a `WarpCollective` shuffle.
880	///
881	/// Reductions and scans need to shuffle the value being combined, but the
882	/// underlying PTX `shfl.sync.{bfly,up,down,idx}` only ships in `b32` and
883	/// `f32` flavors. This trait routes each supported `T` (`u32`, `i32`,
884	/// `f32`) to the right one and bitcasts where required (`i32`).
885	pub trait WarpShuffle: Copy + Sized {
886	    /// Butterfly exchange under the group's mask. See
887	    /// [`WarpCollective::shfl_xor`].
888	    fn shfl_xor_via<G: WarpCollective>(group: &G, value: Self, lane_mask: u32) -> Self;
889	
890	    /// Read from `(my_rank - delta)` within the group. See
891	    /// [`WarpCollective::shfl_up`].
892	    fn shfl_up_via<G: WarpCollective>(group: &G, value: Self, delta: u32) -> Self;
893	}
894	
895	impl WarpShuffle for u32 {
896	    #[inline(always)]
897	    fn shfl_xor_via<G: WarpCollective>(group: &G, value: Self, lane_mask: u32) -> Self {
898	        group.shfl_xor(value, lane_mask)
899	    }
900	    #[inline(always)]
901	    fn shfl_up_via<G: WarpCollective>(group: &G, value: Self, delta: u32) -> Self {
902	        group.shfl_up(value, delta)
903	    }
904	}
