908	    // shuffle sees the same 32 bits, so the round-trip is lossless.
909	    #[inline(always)]
910	    fn shfl_xor_via<G: WarpCollective>(group: &G, value: Self, lane_mask: u32) -> Self {
911	        group.shfl_xor(value as u32, lane_mask) as i32
912	    }
913	    #[inline(always)]
914	    fn shfl_up_via<G: WarpCollective>(group: &G, value: Self, delta: u32) -> Self {
915	        group.shfl_up(value as u32, delta) as i32
916	    }
