930	/// Reduce one value per lane down to a single value across a `WarpTile<N>`.
931	///
932	/// Implements the standard butterfly reduction via `shfl.sync.bfly` —
933	/// `log2(N)` exchanges, each XOR-ing the lane id by `delta` and combining.
934	/// **Every lane in the tile receives the reduced value** (not just lane 0):
935	/// the butterfly converges all lanes onto the same answer, which is the
936	/// usual ergonomic shape and matches CUB's `WarpReduce`.
937	///
938	/// `N` is the tile size (1, 2, 4, 8, 16, or 32) — already validated by
939	/// [`ThreadBlock::tiled_partition`] at construction time.
940	///
941	/// # Convergence
942	///
943	/// All lanes named in the tile's participation mask must reach this call.
944	/// For sub-warp tiles the per-tile mask isolates each tile's reduction
945	/// (lanes outside the mask resolve `shfl.sync` to "own value"), so two
946	/// tiles inside the same warp may interleave their butterflies without
947	/// interference.
948	///
949	/// # Example
950	///
951	/// ```rust,ignore
952	/// use cuda_device::cooperative_groups::{this_thread_block, warp_reduce, ops::Sum};
953	///
954	/// let warp = this_thread_block().tiled_partition::<32>();
955	/// let total: u32 = warp_reduce::<u32, Sum, _>(&warp, my_value);
956	/// // every lane now holds the warp-wide sum
957	/// ```
958	#[inline(always)]
959	pub fn warp_reduce<T, Op, const N: u32>(tile: &WarpTile<N>, value: T) -> T
960	where
961	    T: WarpShuffle,
962	    Op: ops::ReduceOp<T>,
963	{
964	    let mut acc = value;
965	    let mut delta: u32 = N >> 1;
966	    while delta > 0 {
967	        let other = T::shfl_xor_via(tile, acc, delta);
968	        acc = Op::combine(acc, other);
969	        delta >>= 1;
970	    }
971	    acc
972	}
973	
974	/// Inclusive scan across a `WarpTile<N>`. Each lane receives the reduction
975	/// of values from tile-rank `0..=my_rank`.
976	///
977	/// Implemented as a `log2(N)`-step Kogge-Stone scan: at step `delta` each
978	/// lane reads the value from rank `(my_rank - delta)` via `shfl.sync.up`,
979	/// then combines if `my_rank >= delta`. The tile's participation mask
980	/// keeps cross-tile pulls quiet (out-of-mask source ⇒ "own value"), so
981	/// for `N < 32` two tiles in the same warp scan independently.
982	///
983	/// `N` is the tile size (1, 2, 4, 8, 16, or 32).
984	///
985	/// # Example
986	///
987	/// ```rust,ignore
988	/// let warp = this_thread_block().tiled_partition::<32>();
989	/// let prefix: u32 = warp_scan::<u32, Sum, _>(&warp, 1u32);
990	/// // lane k now holds k + 1 (inclusive prefix of all-ones)
991	/// ```
992	#[inline(always)]
993	pub fn warp_scan<T, Op, const N: u32>(tile: &WarpTile<N>, value: T) -> T
994	where
995	    T: WarpShuffle,
996	    Op: ops::ReduceOp<T>,
997	{
998	    let mut acc = value;
999	    let rank = tile.thread_rank();
1000	    let mut delta: u32 = 1;
1001	    while delta < N {
1002	        let other = T::shfl_up_via(tile, acc, delta);
1003	        if rank >= delta {
1004	            acc = Op::combine(acc, other);
1005	        }
1006	        delta <<= 1;
1007	    }
1008	    acc
1009	}
