1011	/// Linear warp index inside the current block. Works for any block dim
1012	/// shape; `warp::warp_id` only handles the 1D case.
1013	#[inline(always)]
1014	fn warp_in_block_linear() -> u32 {
1015	    thread_in_block_linear() / 32
1016	}
