1018	/// Reduce one value per thread down to a single value across a thread block.
1019	///
1020	/// Three-phase shape (the same shape CUB and cuCollections use):
1021	///
1022	/// 1. Each warp warp-reduces its 32 lanes' values via [`warp_reduce`].
1023	/// 2. Lane 0 of each warp writes its warp's total to `smem[warp_id]`,
1024	///    then `block.sync()`.
1025	/// 3. The first warp loads the per-warp totals (filling unused slots with
1026	///    `Op::identity()`), warp-reduces them, and lane 0 writes the
1027	///    block-wide result back to `smem[0]`. After a second `block.sync()`
1028	///    every thread reads `smem[0]`.
1029	///
1030	/// `NUM_WARPS` must equal `BLOCK_SIZE / 32`. It's a `usize` const-generic
1031	/// so it lines up with the [`SharedArray`] length parameter; the
1032	/// compile-time check rejects values outside `1..=32` (i.e. block sizes
1033	/// outside `32..=1024`).
1034	///
1035	/// # Smem reuse
1036	///
1037	/// `smem` is left in an arbitrary state on return. Callers that reuse
1038	/// the same `SharedArray` for a second reduction or scan in the same
1039	/// kernel **must** place a `block.sync()` between calls — otherwise
1040	/// late readers from the first call may race the writes of the second.
1041	///
1042	/// # Why a raw pointer?
1043	///
1044	/// We take `*mut SharedArray<T, NUM_WARPS>` rather than `&mut` so that
1045	/// callers can pass `&raw mut SMEM` directly without an `unsafe` block
1046	/// at the call site (Rust 2024 forbids `&mut` references to a
1047	/// `static mut`, but `&raw mut` is safe). The unsafety — that nothing
1048	/// else aliases the static for the duration of the call — is local to
1049	/// this function body, where the helpers and barriers below preserve it.
1050	///
1051	/// # Example
1052	///
1053	/// ```rust,ignore
1054	/// use cuda_device::cooperative_groups::{block_reduce, ops::Sum, this_thread_block};
1055	/// use cuda_device::SharedArray;
1056	///
1057	/// #[kernel]
1058	/// pub fn my_kernel(...) {
1059	///     // 8 = 256 / 32 warps per 256-thread block
1060	///     static mut SMEM: SharedArray<u32, 8> = SharedArray::UNINIT;
1061	///     let block = this_thread_block();
1062	///     let total = block_reduce::<u32, Sum, _>(&block, my_value, &raw mut SMEM);
1063	///     // every thread now holds the block-wide total
1064	/// }
1065	/// ```
1066	#[inline(always)]
1067	#[allow(clippy::not_unsafe_ptr_arg_deref)]
1068	pub fn block_reduce<T, Op, const NUM_WARPS: usize>(
1069	    block: &ThreadBlock,
1070	    value: T,
1071	    smem: *mut SharedArray<T, NUM_WARPS>,
1072	) -> T
1073	where
1074	    T: WarpShuffle,
1075	    Op: ops::ReduceOp<T>,
1076	{
1077	    const {
1078	        assert!(
1079	            NUM_WARPS > 0 && NUM_WARPS <= 32,
1080	            "block_reduce requires 1..=32 warps (block size 32..=1024)",
1081	        );
1082	    }
1083	
1084	    // SAFETY: The caller (a kernel) hands us a raw pointer to a `static mut
1085	    // SharedArray<T, NUM_WARPS>`. Within this function:
1086	    //   - all writes occur at distinct (warp_id, lane==0) or (lane==0) sites,
1087	    //   - all reads are separated from prior writes by `block.sync()`.
1088	    // No other reference to the static exists for the duration of the call.
1089	    let smem: &mut SharedArray<T, NUM_WARPS> = unsafe { &mut *smem };
1090	
1091	    let warp = block.tiled_partition::<32>();
1092	    let lane = warp.thread_rank();
1093	    let warp_id = warp_in_block_linear();
1094	
1095	    let warp_total = warp_reduce::<T, Op, 32>(&warp, value);
1096	
1097	    if lane == 0 {
1098	        smem[warp_id as usize] = warp_total;
1099	    }
1100	    block.sync();
1101	
1102	    if warp_id == 0 {
1103	        let v: T = if (lane as usize) < NUM_WARPS {
1104	            smem[lane as usize]
1105	        } else {
1106	            <Op as ops::ReduceOp<T>>::identity()
1107	        };
1108	        let block_total = warp_reduce::<T, Op, 32>(&warp, v);
1109	        if lane == 0 {
1110	            smem[0] = block_total;
1111	        }
1112	    }
1113	    block.sync();
1114	
1115	    smem[0]
1116	}
