1118	/// Inclusive scan across a thread block. Thread `i` (in linear order
1119	/// `(z * blockDim.y + y) * blockDim.x + x`) receives the reduction of
1120	/// values from threads `0..=i`.
1121	///
1122	/// Three-phase shape:
1123	///
1124	/// 1. Each warp does an inclusive [`warp_scan`].
1125	/// 2. Lane 31 of each warp writes its warp total (= last value of its
1126	///    inclusive scan) to `smem[warp_id]`, then `block.sync()`.
1127	/// 3. Warp 0 inclusive-scans the warp totals, then converts to an
1128	///    exclusive prefix and writes back to `smem[0..NUM_WARPS]`. After
1129	///    `block.sync()` every thread reads its own warp's exclusive prefix
1130	///    and combines it with its intra-warp inclusive value.
1131	///
1132	/// `NUM_WARPS` must equal `BLOCK_SIZE / 32`. Same `SharedArray` reuse
1133	/// contract as [`block_reduce`] — caller must `block.sync()` before
1134	/// reusing the same smem. Same raw-pointer rationale as well: pass
1135	/// `&raw mut SMEM` from the call site (no `unsafe` block needed).
1136	///
1137	/// # Example
1138	///
1139	/// ```rust,ignore
1140	/// use cuda_device::cooperative_groups::{block_scan, ops::Sum, this_thread_block};
1141	/// use cuda_device::SharedArray;
1142	///
1143	/// #[kernel]
1144	/// pub fn my_kernel(...) {
1145	///     static mut SMEM: SharedArray<u32, 8> = SharedArray::UNINIT;
1146	///     let block = this_thread_block();
1147	///     let prefix = block_scan::<u32, Sum, _>(&block, 1u32, &raw mut SMEM);
1148	///     // thread i now holds i + 1 (inclusive scan of all-ones)
1149	/// }
1150	/// ```
1151	#[inline(always)]
1152	#[allow(clippy::not_unsafe_ptr_arg_deref)]
1153	pub fn block_scan<T, Op, const NUM_WARPS: usize>(
1154	    block: &ThreadBlock,
1155	    value: T,
1156	    smem: *mut SharedArray<T, NUM_WARPS>,
1157	) -> T
1158	where
1159	    T: WarpShuffle,
1160	    Op: ops::ReduceOp<T>,
1161	{
1162	    const {
1163	        assert!(
1164	            NUM_WARPS > 0 && NUM_WARPS <= 32,
1165	            "block_scan requires 1..=32 warps (block size 32..=1024)",
1166	        );
1167	    }
1168	
1169	    // SAFETY: see `block_reduce`.
1170	    let smem: &mut SharedArray<T, NUM_WARPS> = unsafe { &mut *smem };
1171	
1172	    let warp = block.tiled_partition::<32>();
1173	    let lane = warp.thread_rank();
1174	    let warp_id = warp_in_block_linear();
1175	
1176	    let warp_inclusive = warp_scan::<T, Op, 32>(&warp, value);
1177	
1178	    if lane == 31 {
1179	        smem[warp_id as usize] = warp_inclusive;
1180	    }
1181	    block.sync();
1182	
1183	    if warp_id == 0 {
1184	        let v: T = if (lane as usize) < NUM_WARPS {
1185	            smem[lane as usize]
1186	        } else {
1187	            <Op as ops::ReduceOp<T>>::identity()
1188	        };
1189	        let inclusive = warp_scan::<T, Op, 32>(&warp, v);
1190	        // Inclusive -> exclusive: shift right by one lane and force
1191	        // identity at lane 0. shfl_up at lane 0 returns own value, so
1192	        // explicit branch is needed.
1193	        let shifted = T::shfl_up_via(&warp, inclusive, 1);
1194	        let exclusive = if lane == 0 {
1195	            <Op as ops::ReduceOp<T>>::identity()
1196	        } else {
1197	            shifted
1198	        };
1199	        if (lane as usize) < NUM_WARPS {
1200	            smem[lane as usize] = exclusive;
1201	        }
1202	    }
1203	    block.sync();
1204	
1205	    let prefix: T = smem[warp_id as usize];
1206	    Op::combine(prefix, warp_inclusive)
1207	}
